import{_ as e,c as p,o as r,ae as t}from"./chunks/framework.BvcDoAct.js";const s=JSON.parse('{"title":"RAN (MAZZEL)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/14_RAN.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/14_RAN.md"}'),o={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/14_RAN.md"};function n(S,a,A,l,i,M){return r(),p("div",null,[...a[0]||(a[0]=[t('<p>Talk about BMSG - 14</p><h1 id="ran-mazzel" tabindex="-1">RAN (MAZZEL) <a class="header-anchor" href="#ran-mazzel" aria-label="Permalink to &quot;RAN (MAZZEL)&quot;">​</a></h1><h3 id="社长像家人一样爱着艺人。我觉得bmsg能发展壮大的原因就在这里" tabindex="-1">社长像家人一样爱着艺人。我觉得BMSG能发展壮大的原因就在这里 <a class="header-anchor" href="#社长像家人一样爱着艺人。我觉得bmsg能发展壮大的原因就在这里" aria-label="Permalink to &quot;社长像家人一样爱着艺人。我觉得BMSG能发展壮大的原因就在这里&quot;">​</a></h3><p><em>RAN：2002年8月23日出生，熊本县出身</em></p><p><br><br><br> ————RAN，你从《THE FIRST》开始，作为练习生，再到MAZZEL成员，一直以各种形式与SKY-HI有所交集。</p><p>最近我常常会感觉到，选秀时他对我说过的话，一直延续到了现在的自己身上。也越来越多地会有那种瞬间——“正因为当时做了那件事，才有现在的我”。我也逐渐意识到，社长一直是在提前为未来做判断、做引导。而且正因为他本身也是一名艺人，所以一直以来给我的建议都非常有说服力。</p><p>————“当时听的时候并没有完全理解，但随着时间推移才慢慢明白”，主要是指表演方面吗？</p><p>是的，还有MC以及和粉丝的沟通。我以前并不是那种能主动多说话的类型，所以在MC的时候，总有一种没办法打破自我壳子的感觉。不过最近巡演结束后，他跟我说“RAN现在连这些话都能说出来了呢”，那一刻让我很开心，也觉得自己连在展现本真的部分上都在成长。</p><h3 id="在好的意义上放下-过于认真-让现场感更强" tabindex="-1">在好的意义上放下“过于认真”，让现场感更强 <a class="header-anchor" href="#在好的意义上放下-过于认真-让现场感更强" aria-label="Permalink to &quot;在好的意义上放下“过于认真”，让现场感更强&quot;">​</a></h3><p>————MAZZEL经历了首次巡演以及arena公演后有了很大的成长，你觉得特别在哪些方面有所提升？</p><p>我们在好的意义上，放下了“过于认真”。一开始社长对我们的印象，应该是那种比较规整、甚至有点被框住的“很工整的舞台”。他也会说“可以再更放开一点”，但我们一直不知道该怎么去“放开”。后来我们开始思考，希望舞台能更有那种现场的“生感”，于是像RYUKI经常会做的那样，尝试突然把情绪爆发出来，或者去和那些平时不太会有眼神交流的成员互动。从某种意义上说，是一种“不那么拘谨”，也就是根据当下的vibe去产生的现场感。我在arena公演的时候，明显感觉到这一点。也觉得属于MAZZEL的全新舞台形态，正在被慢慢建立起来。</p><p>————你特别尊敬SKY-HI的哪些地方？</p><p>和他长时间相处下来，我一直最深的感受就是，他真的像家人一样去爱每一个艺人。我觉得这正是BMSG能够发展到现在这个规模的原因。还有最近我也越来越觉得，他不骄不躁这一点也是很大的魅力。日高先生会非常清晰地区分“社长”和“艺人SKY-HI”这两个身份。当以艺人之间的身份交流时，他就像一个大哥哥一样，非常亲切，也会结合自己的经验来和我们对话，所以我们也更容易表达自己的想法。他绝不会强加自己的意见，而是在提出自己的想法之后，也会尊重我们的观点。能这么自然做到这一点的社长，真的很厉害。</p><p>————这样的印象，从《THE FIRST》时期开始就没有改变吗？</p><p>完全没有变。我其实也挺常直接给社长发LINE的，做练习生的时候也经常半夜打电话给他。他一直保持着一种很容易让人开口交流的状态，这一点真的很让人安心。</p><p>————作为艺人来说，你憧憬他的哪些方面？</p><p>社长的探究心强到一种“有点过头”的程度。即使已经积累了这么多的职业经验，他依然在不断进化，这样的艺人其实并不多见。而且我觉得，“既然自己是BMSG的领导者，就要带着大家往前走”这种信念，也体现在他的舞台上。在各种意义上，他都在以“我就是BMSG”的姿态，持续站在最前方去证明自己的存在。MAZZEL也一直在思考要如何展现属于自己的色彩，所以真的很憧憬他。</p><p>————随着BMSG本社大楼的建成，公司内部的氛围有什么变化吗？</p><p>BMSG本来就是一个不太讲究前后辈关系、大家更像朋友一样相处的环境，而这种感觉现在变得更强了。只要去艺人休息室或者桑拿，几乎一定会遇到谁，因此和各种人的交流机会也变多了。最近让我有点“抱歉”的是，SOTA经常会约我一起去桑拿，但时间总是对不上。前天我去桑拿的时候，MANATO和SOTA居然在里面睡着了（笑），放松得简直像在自己家一样。另外，社长也很常出现在桑拿和艺人休息室里，有时候练习生也会混在一起。前阵子我还和RYUHEI、KANON以及一位练习生四个人一起去桑拿，总觉得这种画面还挺有意思的（笑）。我当练习生的时候是没有这样的环境的，所以也希望这种氛围以后能一直延续下去。</p><p>————今年9月的「BMSG FES」中，所属艺人再次集结，有什么特别印象深刻的事情吗？</p><p>BMSG MARINE在音乐层面真的让我被“击中”了。ショウちゃん（Aile The Shota）在发挥艺人特色这件事上真的非常厉害。尤其是他在展现edhiii boi原本魅力的同时，又能把他当作“调味料”去带动整体，让整个舞台的完成度都被拉高，我觉得这种制作能力非常强。我想这也是因为ショウちゃん平时有认真去看每一位BMSG的艺人，并且有在好好沟通。那种作品，是不了解对方的话就写不出来的，真的能感受到里面的“爱”。</p><p>————你当时是属于由Novel Core带领的BMSG GAIA吧。</p><p>GAIA的一个“隐藏主题”其实是“我和EIKI要打破自己的壳”。我们两个人都有非常明确的“杀点段落”，但正因为如此，反而很难去找到什么才是最正确的表达方式。GAIA本身是一个个性非常强烈的团队，所以我反而是在做“减法”。虽然我内心当然也有想要很强势表现的一面，但在最开始的段落里，我是有意识地让自己先归零。也正因为这样，我反而更好地掌握了在舞台上如何去处理强弱和节奏的变化，也意识到并不是只有“燃”才是好的。这一点真的要感谢Core（Novel Core）。</p><h3 id="可能性无限的bmsg-也会认真面对全新的尝试" tabindex="-1">可能性无限的BMSG，也会认真面对全新的尝试 <a class="header-anchor" href="#可能性无限的bmsg-也会认真面对全新的尝试" aria-label="Permalink to &quot;可能性无限的BMSG，也会认真面对全新的尝试&quot;">​</a></h3><p>————你和REIKO一起演唱的部分也让人印象很深。</p><p>每年的「BMSG FES」我都会和REIKO有一些合作，而这一次我特别强烈地感觉到这是一个“阶段性的节点”。今年我们一起表演了《MISSION》，我觉得在那个画面中，社长站在那里真的非常美。这既是《MISSIONx2》的一个结束，同时也是我们向大家展现全新故事的一个开始。</p><p>————REIKO现在对你来说，是怎样的存在？</p><p>很难说……大概是像兄弟一样的存在吧。说实话有点“可怕”。明明性格完全不同，但他能看懂我在想什么，我也能看懂他在想什么。我们也有共同的目标，甚至让我觉得，他像是我在艺人活动中的“另一个人格”。这么契合的人真的很少见，所以我也一定还想再和他一起，把只有我们才能做出来的音乐再一次实现出来。</p><p>————作为BMSG的一员，你最感到自豪的是什么？</p><p>这四年来，BMSG的存在感一直在不断提升，但我始终觉得，这是一家“可能性多到不可思议”的公司。在从零开始做新尝试的时候，难免会伴随着恐惧，但只要是我们真正想做的事情，公司都会认真地去面对和支持我们。不被既有形式所束缚，可以从不同的角度去尝试各种可能性，这一点真的非常好。</p><p>————「THE LAST PIECE」也已经启动了。你和RUI、TAIKI、KANON都曾一起参加过选秀，对你来说应该感触更深吧？</p><p>对他们每一个人我都有很深的情感，也会觉得“终于等到这一天了啊……”，内心只有感动和期待。我很清楚他们一路走来付出了多少努力，也了解他们的实力和人品，所以从一个普通观众的角度来说，我也很期待他们最终会成为一个什么样风格的组合。至于MAZZEL，我们也不只是“因为是前辈”，而是希望作为同样的男子组合，能够成为一个更加稳固、更加被认可的存在。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>他从BMSG的黎明期就一直在这里，这件事让我每天都深刻地感到无比珍贵。</p><p>大阪城ホール第二天的RAN，你们看了吗？听过他的歌声了吗？如果没有的话，请现在立刻穿越回过去去看（我知道这要求很乱来）。</p><p>在第一次见到他时浮现在我脑海里的那个RAN，如今就真实地站在那里。能遇到这样的瞬间，对我来说就是最大的喜悦。</p><p>很遗憾，当时在场的观众还不到一万人。那么接下来，就该好好把他的存在感和实力证明给全世界看了吧——明白了，这事就交给我了。已经开始热血沸腾了！</p></blockquote>',33)])])}const m=e(o,[["render",n]]);export{s as __pageData,m as default};
